allow:
Bash(/tmp/inspect_wasm_exports.ts << 'SCRIPT'
/// <reference lib="deno.ns" />

const errno = { success: 0, badf: 8, noent: 44, nosys: 52 };
const compilerBytes = await Deno.readFile\("web/blitz3d-compiler.wasm"\);
let wasmMemoryRef: WebAssembly.Memory | null = null;
const wasi: Record<string, \(...a: any[]\) => any> = {
  args_get: \(\) => 0, args_sizes_get: \(a: number, b: number\) => { if \(wasmMemoryRef\) { const v = new DataView\(wasmMemoryRef.buffer\); v.setUint32\(a,0,true\); v.setUint32\(b,0,true\); } return 0; },
  environ_get: \(\) => 0, environ_sizes_get: \(a: number, b: number\) => { if \(wasmMemoryRef\) { const v = new DataView\(wasmMemoryRef.buffer\); v.setUint32\(a,0,true\); v.setUint32\(b,0,true\); } return 0; },
  fd_write: \(fd: number, iovs: number, iovs_len: number, nw: number\) => { if \(wasmMemoryRef && \(fd===1||fd===2\)\) { const v = new DataView\(wasmMemoryRef.buffer\); let w=0; for\(let i=0;i<iovs_len;i++\) w+=v.getUint32\(iovs+i*8+4,true\); v.setUint32\(nw,w,true\); } return 0; },
  fd_read: \(\)=>0, fd_close: \(\)=>0, fd_seek: \(\)=>0, fd_fdstat_get: \(\)=>0, fd_fdstat_set_flags: \(\)=>0,
  fd_prestat_get: \(\)=>8, fd_prestat_dir_name: \(\)=>8, path_open: \(\)=>44, path_filestat_get: \(\)=>44, proc_exit: \(\)=>0,
  random_get: \(b: number, l: number\) => { if\(wasmMemoryRef\) { const m = new Uint8Array\(wasmMemoryRef.buffer\); for\(let i=0;i<l;i++\) m[b+i]=\(Math.random\(\)*256\)|0; } return 0; },
  clock_time_get: \(_: number, __: bigint, t: number\) => { if\(wasmMemoryRef\) new DataView\(wasmMemoryRef.buffer\).setBigUint64\(t,BigInt\(Date.now\(\)\)*1_000_000n,true\); return 0; },
  poll_oneoff: \(\)=>0, sched_yield: \(\)=>0, clock_res_get: \(\)=>0, fd_filestat_get: \(\)=>0,
  fd_filestat_set_size: \(\)=>0, fd_pread: \(\)=>0, fd_readdir: \(\)=>0, fd_sync: \(\)=>0, fd_tell: \(\)=>0,
  path_create_directory: \(\)=>52, path_filestat_set_times: \(\)=>52, path_link: \(\)=>52,
  path_readlink: \(\)=>52, path_remove_directory: \(\)=>52, path_rename: \(\)=>52,
  path_symlink: \(\)=>52, path_unlink_file: \(\)=>52,
};
const { instance } = await WebAssembly.instantiate\(compilerBytes, { env: {}, wasi_snapshot_preview1: wasi }\);
const ex = instance.exports as any;
wasmMemoryRef = ex.memory;
try { ex._start?.\(\); } catch {}

const workerSrc = await Deno.readTextFile\("web/compiler_worker.ts"\);
const m = workerSrc.match\(/const autoImports = \\[\(.*?\)\\];/s\);
const autoImports = m ? Array.from\(m[1].matchAll\(/"\([^"]+\)"/g\)\).map\(\(x\) => x[1]!\) : [];

const te = new TextEncoder\(\);
const td = new TextDecoder\(\);
const alloc = \(bytes: Uint8Array\) => { const p = ex.malloc\(bytes.length + 1\); new Uint8Array\(ex.memory.buffer, p, bytes.length\).set\(bytes\); return p; };
const alloc4 = \(\) => { const p = ex.malloc\(4\); new DataView\(ex.memory.buffer\).setUint32\(p, 0, true\); return p; };

const src = 'Print "a\(" + 1 + "\)=" + 2';
const srcB = te.encode\(src\);
const optB = te.encode\(JSON.stringify\({ optimize: true, debugInfo: false, sourceMap: false, commandBuffer: false, autoImports }\)\);
const sp = alloc\(srcB\), op = alloc\(optB\), rp = alloc4\(\), rl = alloc4\(\);
const rc = ex.compile_blitz3d\(sp, srcB.length, op, optB.length, rp, rl\);
const v = new DataView\(ex.memory.buffer\);
const rt = td.decode\(new Uint8Array\(ex.memory.buffer, v.getUint32\(rp,true\), v.getUint32\(rl,true\)\)\);
const res = JSON.parse\(rt\);
if \(!res.success\) { console.error\("FAIL:", res.error\); Deno.exit\(1\); }
const wasm = Uint8Array.from\(atob\(res.wasm\), c => c.charCodeAt\(0\)\);
const mod = new WebAssembly.Module\(wasm\);
const exports = WebAssembly.Module.exports\(mod\);
const imports = WebAssembly.Module.imports\(mod\);

console.log\("=== ALL EXPORTS ==="\);
for \(const e of exports\) console.log\(`  ${e.kind} ${e.name}`\);

console.log\("\\n=== ALL IMPORTS \(first 30\) ==="\);
for \(const imp of imports.slice\(0, 30\)\) console.log\(`  ${imp.kind} ${imp.module}.${imp.name}`\);

console.log\("\\n=== StringAlloc in imports? ==="\);
for \(const imp of imports\) if \(/alloc/i.test\(imp.name\)\) console.log\(`  ${imp.module}.${imp.name}`\);
SCRIPT)
